class AudioChunksDataset(Dataset):

    LABELS_EMOTIONS_V1 = [
        "reviewed_frustrated",
        "reviewed_angry",
        "reviewed_sad",
        "reviewed_disgust",
        "reviewed_excited",
        "reviewed_fear",
        "reviewed_neutral",
        "reviewed_surprise",
        "reviewed_happy",
    ]
    LABELS_EMOTIONS_V2 = [
        "merged_negative",
        "merged_sad",
        "merged_positive",
        "merged_neutral"
    ]

    TOP_DB = 80

    # Decay windowed repeat audio by a percentage
    WINDOWED_REPEAT_DECAY = 0.8

    def __init__(
        self,
        df_dataset_audio_chunks: pd.DataFrame,
        db_path: Path,
        sample_rate: int,
        chunk_threshold_seconds: float,
        n_fft: int,
        hop_length: int,
        win_length: int,
        n_mels: int,
        pad_mode: Literal["zero", "windowed_repeat"] = "zero",
        melspec_lib: Literal["torchaudio", "librosa"] = "torchaudio",
        emotion_columns_override: list[str] | None = None
    ):
        self.df_dataset_audio_chunks = df_dataset_audio_chunks
        self.db_path = db_path
        self.sample_rate = sample_rate
        self.chunk_threshold_seconds = chunk_threshold_seconds
        self.n_fft = n_fft
        self.hop_length = hop_length
        self.win_length = win_length
        self.n_mels = n_mels
        self.pad_mode = pad_mode
        self.melspec_lib = melspec_lib

        self.emotion_columns = AudioChunksDataset.LABELS_EMOTIONS_V1 if emotion_columns_override is None else emotion_columns_override

        self.max_frequency = self.sample_rate / 2
        self.maxchunk_sample_frames = int(chunk_threshold_seconds * sample_rate)
        self.max_mel_timeframes = self.maxchunk_sample_frames / self.hop_length + 1

        # Torch audio transforms
        self.mel_spectrogram_transform = T.MelSpectrogram(
            sample_rate=sample_rate,
            n_fft=n_fft,
            hop_length=hop_length,
            win_length=win_length,
            center=True,
            pad_mode="reflect",
            power=2.0,
            norm='slaney',
            n_mels=n_mels,
            mel_scale="htk",
            f_max=self.max_frequency,
        )
        self.amp_to_db_transform = T.AmplitudeToDB(stype="power", top_db=self.TOP_DB)

        self.conn = None

    @property
    def LABELS_EMOTIONS(self):
        return self.emotion_columns

    def __len__(self):
        return len(self.df_dataset_audio_chunks)

    def __getitem__(self, idx: int):
        dataset_row = self.df_dataset_audio_chunks.iloc[idx]
        source_row_index = dataset_row["source_dataset_row_index"]

        audio_array, sr = self.get_item_audio_bytes(idx)

        if self.melspec_lib == "librosa":
            # Calculate log mel spectrogram
            mel_spec = librosa.feature.melspectrogram(
                y=audio_array,
                sr=sr,
                n_fft=self.n_fft,
                hop_length=self.hop_length,
                win_length=self.win_length,
                n_mels=self.n_mels,
                fmax=self.max_frequency,
            )

            # Convert power scale → log scale (closer to human hearing)
            log_mel_spec = librosa.power_to_db(mel_spec, ref=np.max)
            features = torch.tensor(log_mel_spec, dtype=torch.float32)
        else:
            audio_tensor = torch.tensor(audio_array, dtype=torch.float32)

            # torchaudio expects (channels, time)
            audio_tensor = audio_tensor.unsqueeze(0) # mono

            mel_specs = self.mel_spectrogram_transform(audio_tensor)

            # Get the mel matrix for the only channel and
            # convert power scale → log scale (closer to human hearing)
            features = self.amp_to_db_transform(mel_specs[0])
            features = features - features.max()  # now in (-80, 0] like librosa

        labels = self._build_labels_tensor(dataset_row)

        assert features.shape[0] == self.n_mels
        assert features.shape[1] == self.max_mel_timeframes
        assert len(labels) == len(self.LABELS_EMOTIONS)

        return features, labels

    def get_item_audio_bytes(self, idx: int) -> tuple[npt.NDArray, int]:
        dataset_row = self.df_dataset_audio_chunks.iloc[idx]
        db_row = self._fetch_db_record(dataset_row["source_dataset_row_index"])

        audio_bytes = db_row["audio_bytes"]

        # Decode audio using soundfile
        audio_array, sr = sf.read(io.BytesIO(audio_bytes), dtype="float32")

        # Slice the audio
        start = int(dataset_row["start_sample_offset"])
        end = int(dataset_row["end_sample_offset"])
        sliced_audio = audio_array[start:end]

        # Waveform padding
        if len(sliced_audio) < self.maxchunk_sample_frames:
            sliced_audio = self._pad_waveform(sliced_audio, source_waveform=audio_array)

        assert len(sliced_audio) == self.maxchunk_sample_frames

        return sliced_audio, sr

    def play_item_audio(self, idx: int):
        audio_array, sr = self.get_item_audio_bytes(idx)
        display(Audio(audio_array, rate=sr))

    def plot_melspectrogram(self, idx: int):
        dataset_row = self.df_dataset_audio_chunks.iloc[idx]
        db_row = self._fetch_db_record(dataset_row["source_dataset_row_index"])

        features, _ = self[idx]
        spec = features.numpy().astype(np.float32)

        fig, ax = plt.subplots(figsize=(10, 4))

        total_chunk_parts = dataset_row.get("total_chunk_parts")
        chunk_part_idx = dataset_row.get("chunk_part_idx")
        if total_chunk_parts > 0:
            title = f"Chunk {int(chunk_part_idx) + 1} of {int(total_chunk_parts)}"
        else:
            title = "Single-Chunk"
        title += f'  |  {db_row["major_emotion"]}'

        img = ax.imshow(spec, aspect="auto", origin="lower", cmap="magma")
        ax.set_title(title)
        ax.set_xlabel("Time frames")
        ax.set_ylabel("Mel bands")
        plt.colorbar(img, ax=ax, format="%+2.0f dB")

        transcription = db_row["transcription"]
        if transcription:
            plt.suptitle(f'"{transcription.strip()}"', fontsize=11)

        plt.tight_layout()
        plt.show()

    def get_labels_emotion_name(self, idx: int) -> str:
        return self.LABELS_EMOTIONS[idx]

    def _get_conn(self):
        if self.conn is None:
            self.conn = sqlite3.connect(self.db_path)
            self.conn.row_factory = sqlite3.Row
        return self.conn

    def _fetch_db_record(self, source_row_index: int) -> dict:
        conn = self._get_conn()
        cursor = conn.cursor()
        cursor.execute(
            "SELECT audio_bytes, transcription, major_emotion FROM iemocap_dataset WHERE row_index = ?",
            (int(source_row_index),),
        )
        db_row = cursor.fetchone()

        if db_row is None:
            raise ValueError(f"Could not find row_index {source_row_index} in DB.")

        return db_row

    def _build_labels_tensor(self, row: pd.Series | dict) -> torch.Tensor:
        return torch.tensor(
            [row[emo_col] for emo_col in self.LABELS_EMOTIONS],
            dtype=torch.float32,
        )

    def merge_source_emotions(self):
        if not hasattr(self, 'original_source_df'):
            self.original_source_df = self.df_dataset_audio_chunks.copy()

        # Create new columns by applying the function
        new_features_df = self.original_source_df.apply(AudioChunksDataset.merge_emotions_by_row, axis=1)

        # Join the new columns back to your original DataFrame
        self.df_dataset_audio_chunks = pd.concat([self.original_source_df, new_features_df], axis=1)

    def _pad_waveform(self, sliced_audio: npt.NDArray, source_waveform: npt.NDArray) -> npt.NDArray:
        # Length of the audio chunk left to be padded.
        sliced_audio_length = len(sliced_audio)
        # Produce a new zero-padded array with the expected frame size.
        padded_waveform = np.pad(sliced_audio, (0, self.maxchunk_sample_frames - sliced_audio_length))
        if self.pad_mode == "windowed_repeat":
            padded_waveform = self._pad_with_widowed_repeat(source_waveform, padded_waveform, repeat_start_offset=sliced_audio_length)
        return padded_waveform

    def _pad_with_widowed_repeat(self, source_waveform: npt.NDArray, padded_waveform: npt.NDArray, repeat_start_offset: int) -> npt.NDArray:
        chunk_size_left_to_pad = self.maxchunk_sample_frames - repeat_start_offset

        for i in range(chunk_size_left_to_pad):
            padded_offset = i + repeat_start_offset
            # Using modulo operator to repeat the source waveform as many times as need.
            # e.g. We have a 3 second padded_waveform, but our source_waveform is only 1 second long,
            #      therefore we need to repeat it 2 more times.
            source_offset = i % len(source_waveform)
            padded_waveform[padded_offset] = source_waveform[source_offset] * self.WINDOWED_REPEAT_DECAY

        return padded_waveform


