def merge_emotions_by_row_v1(row):
    original_emotions = AudioChunksDataset.LABELS_EMOTIONS_V1
    original_emotion_score_map = { emo.split('_')[-1] : row[emo] for emo in original_emotions}

    merged_emotions = AudioChunksDataset.LABELS_EMOTIONS_V2
    merged_emotions_scores = [
        original_emotion_score_map["frustrated"] + original_emotion_score_map["angry"],
        original_emotion_score_map["sad"],
        original_emotion_score_map["happy"],
        original_emotion_score_map["neutral"],
    ]

    # Primary emotions (frustrated, angry, sad, happy) can be
    # modified or complemented by secondary reactions (excited, surprised, fearful, disgusted).
    # - excited + angry: https://iemocap-files.plumberslog.com/compressed_audio/Ses05M_script03_2_M001.mp3
    # - surprised + excited + happy: https://iemocap-files.plumberslog.com/compressed_audio/Ses05M_script01_3_M012.mp3

    mixed_emotion_scores_sum = original_emotion_score_map["disgust"] + original_emotion_score_map["excited"] + original_emotion_score_map["fear"] + original_emotion_score_map["surprise"]

    orignal_major_emotion = row["reviewed_major_emotion"]
    if orignal_major_emotion in ["frustrated", "angry"]:
        merged_emotions_scores[0] += mixed_emotion_scores_sum
    elif orignal_major_emotion == "sad":
        merged_emotions_scores[1] += mixed_emotion_scores_sum
    elif orignal_major_emotion == "happy":
        merged_emotions_scores[2] += mixed_emotion_scores_sum
    elif orignal_major_emotion == "neutral":
        merged_emotions_scores[3] += mixed_emotion_scores_sum
    else:
        # Find the most active merged emotion and add the mixed_emotion_scores to it.
        # 1. Get indices that sort ascending for list values.
        # 2. Reverse it with [[::-1]] for descending order.
        # Input: [4, 6, 2] => Output: [1, 0, 2]
        descending_indices = np.argsort(merged_emotions_scores)[::-1]

        max_score_indices = [descending_indices[0]]
        max_score = merged_emotions_scores[max_score_indices[0]]
        for idx in descending_indices[1:]:
            if merged_emotions_scores[idx] == max_score:
                max_score_indices.append(idx)

        # If tied in max score, weight more other merged emotions different than "neutral".
        if len(max_score_indices) > 1 and (neutral_idx := merged_emotions.index("merged_neutral")) and neutral_idx in max_score_indices:
            max_score_indices.remove(neutral_idx)

        # Note there are odd cases like, happy + sad, example: https://iemocap-files.plumberslog.com/compressed_audio/Ses01F_script03_1_F008.mp3

        # Distribute `mixed_emotion_scores_sum` between emotions if more than one has the max score.
        for idx in max_score_indices:
            merged_emotions_scores[idx] += mixed_emotion_scores_sum / len(max_score_indices)

    descending_indices = np.argsort(merged_emotions_scores)[::-1]
    highest_emotion_idx = descending_indices[0]
    merged_major_emotion = merged_emotions[highest_emotion_idx].split('_')[-1]
    second_highest_emotion_idx = descending_indices[1]
    prediction_margin = merged_emotions_scores[highest_emotion_idx] - merged_emotions_scores[second_highest_emotion_idx]

    margin_zero_major_emotions = None
    if 0 <= prediction_margin < 0.05:
        second_merged_major_emotion = merged_emotions[second_highest_emotion_idx].split('_')[-1]
        margin_zero_major_emotions = '+'.join(sorted([merged_major_emotion, second_merged_major_emotion]))

    merged_emotions_scores_columns = {}
    for idx, emo_col_name in enumerate(merged_emotions):
        merged_emotions_scores_columns[emo_col_name] = merged_emotions_scores[idx]

    return pd.Series(
        {
            "merged_major_emotion": merged_major_emotion,
            "original_to_merged_comparison": f"{orignal_major_emotion}__{merged_major_emotion}",
            "prediction_margin": prediction_margin,
            "margin_zero_major_emotions": margin_zero_major_emotions,
        } | merged_emotions_scores_columns
    )

